package eu.wohlben.qits.domain.command.entity;

/** How a session entered a command's {@link AgentSessionRef session list}. */
public enum AgentSessionSource {
  /** A fresh session, its ID generated by qits and pinned at launch. */
  PINNED,
  /** A relaunch continuing an existing session in place (same ID, transcript appended). */
  RESUMED,
  /** A branch launch: a fresh pinned ID that inherited another session's history. */
  FORKED,
  /** Reported by the harness's SessionStart hook after an in-TUI session change (e.g. /resume). */
  SWITCHED,
  /** Reported by the harness because the launch could not pin a session id (Kimi Code). */
  REPORTED
}
